import sys
import itertools

def is_palindrome(sub):
    return sub == sub[::-1]

def contains_palindrome(s, k):
    for i in range(len(s) - k + 1):
        substring = s[i:i+k]
        if is_palindrome(substring):
            return True
    return False

def main():
    input = sys.stdin.read().split()
    N = int(input[0])
    K = int(input[1])
    S = input[2]

    unique_perms = set(itertools.permutations(S))
    count = 0

    for perm in unique_perms:
        perm_str = ''.join(perm)
        if not contains_palindrome(perm_str, K):
            count += 1

    print(count)

if __name__ == "__main__":
    main()
